/**
 * [compaction-dual-output:v1]
 * OpenCode local plugin to inject a dual-block compaction directive.
 */
export const CompactionDualOutput = async () => {
  return {
    name: "compaction-dual-output",
    hooks: {
      "experimental.session.compacting": async (input, output) => {
        const marker = "[compaction-dual-output:v1]";

        if (!Array.isArray(output.context)) {
          output.context = [];
        }

        // Idempotence check
        if (output.context.some(line => typeof line === 'string' && line.includes(marker))) {
          return;
        }

